from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
import pandas as pd
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# Model parameters
IMG_HEIGHT = 180
IMG_WIDTH = 180
BATCH_SIZE = 32
EPOCHS = 10

# Initialize an empty model
model = None

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file uploaded'}), 400
    
    file = request.files['file']
    filename = secure_filename(file.filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(filepath)
    
    if filename.endswith('.csv'):
        train_model(filepath)
        
    return jsonify({'message': 'File uploaded successfully'}), 200

def train_model(csv_path):
    global model
    data = pd.read_csv(csv_path)
    
    # Assuming the CSV contains 'image_path' and 'label' columns
    images = data['image_path'].values
    labels = data['label'].values
    
    train_data = tf.keras.preprocessing.image_dataset_from_directory(
        'path_to_image_dir', 
        image_size=(IMG_HEIGHT, IMG_WIDTH), 
        batch_size=BATCH_SIZE
    )
    
    # Define model
    model = keras.Sequential([
        layers.Rescaling(1./255, input_shape=(IMG_HEIGHT, IMG_WIDTH, 3)),
        layers.Conv2D(32, 3, activation='relu'),
        layers.MaxPooling2D(),
        layers.Conv2D(64, 3, activation='relu'),
        layers.MaxPooling2D(),
        layers.Conv2D(128, 3, activation='relu'),
        layers.MaxPooling2D(),
        layers.Flatten(),
        layers.Dense(128, activation='relu'),
        layers.Dense(len(set(labels)), activation='softmax')
    ])
    
    model.compile(optimizer='adam', 
                  loss='sparse_categorical_crossentropy', 
                  metrics=['accuracy'])
    
    model.fit(train_data, epochs=EPOCHS)

@app.route('/predict', methods=['POST'])
def predict():
    if model is None:
        return jsonify({'error': 'Model is not trained yet'}), 400
    
    file = request.files['file']
    img_path = secure_filename(file.filename)
    img_path = os.path.join(app.config['UPLOAD_FOLDER'], img_path)
    file.save(img_path)
    
    img = keras.preprocessing.image.load_img(img_path, target_size=(IMG_HEIGHT, IMG_WIDTH))
    img_array = keras.preprocessing.image.img_to_array(img) / 255.0
    img_array = tf.expand_dims(img_array, 0)  # Create batch dimension
    
    predictions = model.predict(img_array)
    predicted_label = tf.argmax(predictions[0]).numpy()
    
    return jsonify({'predicted_label': int(predicted_label)}), 200

if __name__ == '__main__':
    app.run(debug=True)